import React, { useState, useEffect } from 'react';
import { View, StyleSheet, FlatList, Alert } from 'react-native';
import { Title, Button, Paragraph, Chip } from 'react-native-paper';
import api from '../services/api';

export default function BookingScreen({ route, navigation }) {
  const { show, showtime } = route.params;
  const [seats, setSeats] = useState([]);
  const [selectedSeats, setSelectedSeats] = useState([]);

  useEffect(() => {
    const fetchSeats = async () => {
      try {
        const response = await api.get(`/shows/showtimes/${showtime.show_time_id}/seats`);
        setSeats(response.data);
      } catch (e) {
        console.error(e);
      }
    };
    fetchSeats();
  }, [showtime.show_time_id]);

  const toggleSeat = (id) => {
    if (selectedSeats.includes(id)) {
      setSelectedSeats(selectedSeats.filter(s => s !== id));
    } else {
      setSelectedSeats([...selectedSeats, id]);
    }
  };

  const handleBooking = async () => {
    if (selectedSeats.length === 0) {
      if (Platform.OS === 'web') {
        alert('Please select at least one seat.');
      } else {
        Alert.alert('Selection Required', 'Please select at least one seat.');
      }
      return;
    }

    console.log("Attempting booking...");
    try {
      const response = await api.post('/reservations', {
        showId: show.show_id,
        showTimeId: showtime.show_time_id,
        seats: selectedSeats
      });

      console.log("Booking response:", response.data);

      if (Platform.OS === 'web') {
        alert('Booking confirmed! You will be redirected to your profile.');
        navigation.navigate('Profile');
      } else {
        Alert.alert('Success', 'Booking confirmed!', [
          { text: 'View My Bookings', onPress: () => navigation.navigate('Profile') }
        ]);
      }
    } catch (e) {
      console.error("Booking catch error:", e);
      if (Platform.OS === 'web') {
        alert('Booking failed. The server might be down or there is a database issue.');
      } else {
        Alert.alert('Error', 'Booking failed. Try again.');
      }
    }
  };

  return (
    <View style={styles.container}>
      <Title>Select Seats for {show.title}</Title>
      <Paragraph>{new Date(showtime.show_date).toDateString()} at {showtime.show_time}</Paragraph>

      <View style={styles.legend}>
         <Chip style={styles.chipAvailable}>Available</Chip>
         <Chip style={styles.chipSelected}>Selected</Chip>
         <Chip style={styles.chipOccupied}>Occupied</Chip>
      </View>

      <FlatList
        data={seats}
        numColumns={5}
        keyExtractor={(item) => item.id}
        renderItem={({ item }) => (
          <Button
            mode={selectedSeats.includes(item.id) ? "contained" : "outlined"}
            disabled={!item.available}
            onPress={() => toggleSeat(item.id)}
            style={styles.seat}
            labelStyle={styles.seatLabel}
          >
            {item.id}
          </Button>
        )}
        contentContainerStyle={styles.grid}
      />

      <View style={styles.footer}>
        <Paragraph style={styles.totalText}>Total Price: {selectedSeats.length * showtime.price}€</Paragraph>
        <Button mode="contained" onPress={handleBooking} contentStyle={{ height: 50 }}>Confirm Booking</Button>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, padding: 20, backgroundColor: '#fff' },
  legend: { flexDirection: 'row', justifyContent: 'space-around', marginVertical: 15 },
  grid: { alignItems: 'center', paddingBottom: 20 },
  seat: { margin: 5, width: 65, height: 45, justifyContent: 'center' },
  seatLabel: { fontSize: 12, fontWeight: 'bold', color: '#000' },
  footer: { paddingVertical: 20, borderTopWidth: 1, borderColor: '#eee', backgroundColor: '#fff' },
  totalText: { fontSize: 18, fontWeight: 'bold', color: '#000', marginBottom: 10 },
  chipAvailable: { backgroundColor: '#e0e0e0', borderWidth: 1, borderColor: '#ccc' },
  chipSelected: { backgroundColor: '#6200ee', borderWidth: 1, borderColor: '#3700b3' },
  chipOccupied: { backgroundColor: '#ffcdd2', borderWidth: 1, borderColor: '#e57373' }
});
